class MyHashSet {
    static const int BASE = 769;
    vector<list<int>> data;
    int hash(int key) { return key % BASE; }
public:
    MyHashSet() : data(BASE) {}
    void add(int key) {
        int h = hash(key);
        for (int x : data[h]) if (x == key) return;
        data[h].push_back(key);
    }
    void remove(int key) {
        int h = hash(key);
        data[h].remove(key);
    }
    bool contains(int key) {
        int h = hash(key);
        for (int x : data[h]) if (x == key) return true;
        return false;
    }
};

